#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <stdbool.h>

int main()
{
    int n;
    scanf("%d", &n);

    if (n <= 0) {
        printf("invalid\n");
        return 0;
    }

    int positions[n];
    bool valid = true;

    for (int i = 0; i < n; i++) {
        scanf("%d", &positions[i]);

        if (positions[i] < 0) {
            valid = false;
        }

        if (i > 0 && positions[i] <= positions[i - 1]) {
            valid = false;
        }
    }

    int m;
    scanf("%d", &m);

    if (m < 0) {
        valid = false;
    }

    if (!valid) {
        printf("invalid\n");
        return 0;
    }

    int last = 0;

    for (int i = 0; i < n; i++) {
        if (positions[i] - last > m) {
            printf("no\n");
            return 0;
        }
        last = positions[i];
    }

    printf("yes\n");

    return 0;
}
